class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        size_t firstStar = p.find('*');
        size_t secondStar = p.find('*', firstStar + 1);
        string prefix = p.substr(0, firstStar);
        string middle = p.substr(firstStar + 1, secondStar - firstStar - 1);
        string suffix = p.substr(secondStar + 1);

        int n = s.size();
        int minLen = -1;

        for (int i = 0; i <= n; ++i) {
            if (i < prefix.size() || !equal(prefix.begin(), prefix.end(), s.begin() + i - prefix.size())) continue;
            for (int j = i; j <= n; ++j) {
                if (j < suffix.size() || !equal(suffix.rbegin(), suffix.rend(), s.begin() + j)) continue;
                int start = i - prefix.size();
                int end = j + suffix.size();
                if (start > end) continue;
                string sub = s.substr(start, end - start);
                if (sub.find(middle) != string::npos) {
                    int len = end - start;
                    if (minLen == -1 || len < minLen) minLen = len;
                }
            }
        }

        if (minLen == -1 && prefix.empty() && middle.empty() && suffix.empty()) return 0;
        return minLen;
    }
};
